"""
MABE Bootstrap: De Novo Generator + Discovery API + Scaffold Hopping

Run: python3 bootstrap_de_novo_hop.py

Creates/overwrites:
  core/de_novo_generator.py       — 28 backbones x 35 arms + bioisostere table
                                     + scaffold_hop() + bioisosteric_replace()
                                     + hop_and_score()
  core/design_engine_v2.py        — discover_binders(seed_smiles=) wired
  tests/test_de_novo_generator.py — 63 tests
  tests/test_design_engine_v2.py  — 16 tests

New API:
  scaffold_hop(smiles, metal) → same donors, different backbone
  bioisosteric_replace(smiles, metal) → same backbone class, swapped donor groups
  hop_and_score(smiles, metal, mode="both") → scored variants
  discover_binders(metal, seed_smiles="NCCN") → library + generated + hopped

Total: 665 passed, 50 skipped, 0 failed
"""
import base64, pathlib

FILES = {
    "core/de_novo_generator.py": "",
    "tests/test_de_novo_generator.py": "",
    "core/design_engine_v2.py": "",
    "tests/test_design_engine_v2.py": "",
}

def main():
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  Wrote {path} ({len(base64.b64decode(b64)):,} bytes)")
    print()
    print("  Run: python3 -m pytest tests/test_de_novo_generator.py tests/test_design_engine_v2.py -v")

if __name__ == "__main__":
    main()